import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';

type UserRole = 'admin' | 'employee';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './login/login.component.html',
  styleUrls: ['./login.component.css']
})
export class LoginComponent implements OnInit {
  error = '';
  form = this.fb.group({
    username: ['', Validators.required],
    password: ['', Validators.required]
  });

  constructor(
    private fb: FormBuilder,
    private auth: AuthService,
    private router: Router
  ) {}

  ngOnInit(): void {
    if (this.auth.isLoggedIn()) {
      this.redirectByRole();
    }
  }

  login(): void {
    this.error = '';

    const username = this.form.value.username ?? '';
    const password = this.form.value.password ?? '';

    if (!username || !password) {
      this.error = 'Veuillez saisir un nom et un mot de passe.';
      return;
    }

    const ok = this.auth.login(username, password);
    if (!ok) {
      this.error = 'Identifiants incorrects.';
      return;
    }

    this.redirectByRole();
  }

  loginAs(role: UserRole): void {
    if (role === 'admin') {
      this.form.setValue({ username: 'admin', password: 'admin123' });
    } else {
      this.form.setValue({ username: 'employee', password: 'emp123' });
    }

    this.login();
  }

  private redirectByRole(): void {
    const role = this.auth.role();
    this.router.navigateByUrl(role === 'employee' ? '/stock' : '/invoices');
  }
}
